--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ ... @@
+/**
+ * Draws a minimap overview panel in the corner of the screen.
+ * Shows all rooms as colored rectangles with dots for character positions.
+ * Highlights the currently viewed room.
+ *
+ * @param ctx CanvasRenderingContext2D to draw on
+ * @param castleRooms Array of room info objects: { id: string; type: CharacterType; x: number; y: number; w: number; h: number; }
+ * @param characters Array of character info objects: { id: string; type: CharacterType; roomId: string; x: number; y: number; }
+ * @param currentRoomId The id of the currently viewed room to highlight
+ * @param screenWidth Width of the main canvas/screen
+ * @param screenHeight Height of the main canvas/screen
+ */
+export function drawMinimap(
+  ctx: CanvasRenderingContext2D,
+  castleRooms: { id: string; type: CharacterType; x: number; y: number; w: number; h: number; }[],
+  characters: { id: string; type: CharacterType; roomId: string; x: number; y: number; }[],
+  currentRoomId: string,
+  screenWidth: number,
+  screenHeight: number,
+) {
+  // Minimap size and position
+  const minimapWidth = 200;
+  const minimapHeight = 150;
+  const padding = 10;
+  const minimapX = screenWidth - minimapWidth - padding;
+  const minimapY = padding;
+
+  // Determine bounding box of all rooms to scale minimap accordingly
+  if (castleRooms.length === 0) return;
+  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
+  for (const room of castleRooms) {
+    minX = Math.min(minX, room.x);
+    minY = Math.min(minY, room.y);
+    maxX = Math.max(maxX, room.x + room.w);
+    maxY = Math.max(maxY, room.y + room.h);
+  }
+  const castleWidth = maxX - minX;
+  const castleHeight = maxY - minY;
+
+  // Calculate scale to fit all rooms inside minimap area with some margin
+  const scaleX = minimapWidth / castleWidth;
+  const scaleY = minimapHeight / castleHeight;
+  const scale = Math.min(scaleX, scaleY);
+
+  // Background panel
+  ctx.save();
+  ctx.fillStyle = 'rgba(20, 20, 30, 0.8)';
+  ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
+  ctx.lineWidth = 2;
+  ctx.shadowColor = 'rgba(0,0,0,0.8)';
+  ctx.shadowBlur = 6;
+  ctx.fillRect(minimapX, minimapY, minimapWidth, minimapHeight);
+  ctx.strokeRect(minimapX, minimapY, minimapWidth, minimapHeight);
+  ctx.shadowBlur = 0;
+
+  // Draw rooms as rectangles
+  for (const room of castleRooms) {
+    const rx = minimapX + (room.x - minX) * scale;
+    const ry = minimapY + (room.y - minY) * scale;
+    const rw = room.w * scale;
+    const rh = room.h * scale;
+
+    // Room fill color based on type (lighter)
+    const baseColors: Record<CharacterType, string> = {
+      king: '#7a5a9a',
+      nobility: '#6a7a9a',
+      knight: '#5a6a7a',
+      squire: '#5a7a5a',
+      healer: '#5a7a7a',
+      sentinel: '#7a7a5a',
+      scribe: '#7a5a5a',
+      judge: '#9a7a5a',
+      blacksmith: '#9a5a5a',
+    };
+    const fillColor = baseColors[room.type] || '#666666';
+    ctx.fillStyle = fillColor;
+    ctx.fillRect(rx, ry, rw, rh);
+
+    // Border for rooms
+    ctx.strokeStyle = 'rgba(255,255,255,0.4)';
+    ctx.lineWidth = 1;
+    ctx.strokeRect(rx, ry, rw, rh);
+  }
+
+  // Highlight current room with a bright border
+  const currentRoom = castleRooms.find(r => r.id === currentRoomId);
+  if (currentRoom) {
+    const crx = minimapX + (currentRoom.x - minX) * scale;
+    const cry = minimapY + (currentRoom.y - minY) * scale;
+    const crw = currentRoom.w * scale;
+    const crh = currentRoom.h * scale;
+    ctx.strokeStyle = '#ffd700';
+    ctx.lineWidth = 3;
+    ctx.strokeRect(crx, cry, crw, crh);
+  }
+
+  // Draw characters as dots inside their rooms
+  for (const char of characters) {
+    const room = castleRooms.find(r => r.id === char.roomId);
+    if (!room) continue;
+    const charX = minimapX + (room.x - minX) * scale + char.x * scale;
+    const charY = minimapY + (room.y - minY) * scale + char.y * scale;
+    const color = PALETTE_MAP[char.type]?.P || '#ffffff';
+    ctx.fillStyle = color;
+    ctx.beginPath();
+    ctx.arc(charX, charY, 3, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.strokeStyle = 'rgba(0,0,0,0.5)';
+    ctx.lineWidth = 1;
+    ctx.stroke();
+  }
+
+  ctx.restore();
+}
+
